import{E as e,R as t,U as n,_ as r,et as i,f as a,h as o,pt as s,v as c,x as l,y as u,z as d}from"./runtime-core.esm-bundler-ChtuvW5g.js";var f={class:`ant-doc vp-doc`},p=l({__name:`index.zh-CN`,setup(l,{expose:p}){let m={title:`ProLayout`,frontmatter:{category:`Components`,group:`布局`,title:`ProLayout`,subtitle:`高级布局`,cover:`https://gw.alipayobjects.com/zos/antfincdn/4n5H%24UX%24j/bianzu%2525204.svg`,coverDark:`https://gw.alipayobjects.com/zos/antfincdn/4n5H%24UX%24j/bianzu%2525204.svg`},headers:[{level:2,title:`何时使用`,slug:`when-to-use`,link:`#when-to-use`,children:[]},{level:2,title:`代码演示`,slug:`examples`,link:`#examples`,children:[{level:3,title:`基础使用`,slug:`layout-demo-basic`,link:`#layout-demo-basic`,children:[]},{level:3,title:`高级帮助`,slug:`layout-demo-help`,link:`#layout-demo-help`,children:[]}]},{level:2,title:`API`,slug:`api`,link:`#api`,children:[{level:3,title:`ProLayout`,slug:`prolayout`,link:`#prolayout`,children:[]},{level:3,title:`menu`,slug:`menu`,link:`#menu`,children:[]},{level:3,title:`SettingDrawer`,slug:`settingdrawer`,link:`#settingdrawer`,children:[]},{level:3,title:`事件`,slug:`events`,link:`#events`,children:[]},{level:3,title:`插槽`,slug:`slots`,link:`#slots`,children:[]}]},{level:2,title:`主题变量（Design Token）`,slug:`theme-variables`,link:`#theme-variables`,children:[]},{level:2,title:`FAQ`,slug:`faq`,link:`#faq`,children:[{level:3,title:`如何选择布局形态？`,slug:`layout-mode`,link:`#layout-mode`,children:[]},{level:3,title:`如何隐藏不需要的区域？`,slug:`custom-layout`,link:`#custom-layout`,children:[]}]}],description:``},h={category:`Components`,group:`布局`,title:`ProLayout`,subtitle:`高级布局`,cover:`https://gw.alipayobjects.com/zos/antfincdn/4n5H%24UX%24j/bianzu%2525204.svg`,coverDark:`https://gw.alipayobjects.com/zos/antfincdn/4n5H%24UX%24j/bianzu%2525204.svg`},g=s({});d(`__pageData__`,e=>{g.value=e});let _=e(`__pageData__`,null);return _&&_(m),d(`__pageInfo__`,m),p({frontmatter:h,pageData:m}),(e,s)=>{let l=n(`demo`),d=n(`demo-group`),p=n(`ComponentTokenTable`);return t(),o(`div`,f,[s[2]||=r(`<p>ProLayout 提供中后台应用常用的页面框架能力：顶部栏、侧边菜单、内容区、页脚、面包屑、页面标题和运行时布局配置。它会根据路由数据自动生成菜单，并将页面上下文提供给 PageContainer、FooterToolbar 等组件。</p><p>ProLayout 支持 <code>side</code>、<code>top</code>、<code>mix</code> 和 <code>left</code> 四种布局形态。<code>left</code> 布局会将一级菜单固定在最左侧，二级菜单按当前一级菜单展开，适合导航层级较深且需要快速切换一级模块的系统。</p><h2 id="when-to-use" tabindex="-1">何时使用 <a class="header-anchor" href="#when-to-use" aria-label="Permalink to &quot;何时使用 {#when-to-use}&quot;">​</a></h2><ul><li>需要搭建标准中后台应用外框时。</li><li>需要从路由数据自动生成菜单、面包屑和页面标题时。</li><li>需要在运行时切换布局、主题、固定 Header 或固定 Sider 时。</li><li>需要配合 PageContainer 统一页面标题、面包屑、内容区和页脚工具栏时。</li><li>需要通过 <code>headerRender</code>、<code>menuRender</code>、<code>menuHeaderRender</code> 等渲染函数定制布局局部区域时。</li></ul><h2 id="examples" tabindex="-1">代码演示 <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;代码演示 {#examples}&quot;">​</a></h2>`,5),u(d,null,{default:i(()=>[u(l,{src:`/src/pages/components/layout/demo/basic.vue`,iframe:`550`},{default:i(()=>[...s[0]||=[c(`基础使用`,-1)]]),_:1}),u(l,{src:`/src/pages/components/layout/demo/help.vue`,iframe:`360`},{default:i(()=>[...s[1]||=[c(`高级帮助`,-1)]]),_:1})]),_:1}),s[3]||=r(`<h2 id="api" tabindex="-1">API <a class="header-anchor" href="#api" aria-label="Permalink to &quot;API&quot;">​</a></h2><h3 id="prolayout" tabindex="-1">ProLayout <a class="header-anchor" href="#prolayout" aria-label="Permalink to &quot;ProLayout {#prolayout}&quot;">​</a></h3><blockquote><p>所有以 <code>Render</code> 为后缀的方法都可以通过传入 <code>false</code> 来关闭对应区域渲染，也可以通过同名插槽进行定制。</p></blockquote><table class="component-table-api"><thead><tr><th>属性</th><th>说明</th><th>类型</th><th>默认值</th><th>版本</th></tr></thead><tbody><tr><td>title</td><td>布局标题，会用于菜单头和浏览器标题</td><td><code>string | false</code></td><td><code>Antdv Next Pro</code></td><td>-</td></tr><tr><td>logo</td><td>菜单头 Logo，支持图片地址、VNode、渲染函数或 <code>false</code></td><td><code>VueNode | false</code></td><td>内置 Logo</td><td>-</td></tr><tr><td>layout</td><td>布局形态</td><td><code>&#39;side&#39; | &#39;top&#39; | &#39;mix&#39; | &#39;left&#39;</code></td><td><code>&#39;side&#39;</code></td><td>-</td></tr><tr><td>navTheme</td><td>导航菜单主题</td><td><code>&#39;light&#39; | &#39;dark&#39; | &#39;realDark&#39;</code></td><td><code>&#39;dark&#39;</code></td><td>-</td></tr><tr><td>contentWidth</td><td>内容区宽度，仅在 <code>layout=&quot;top&quot;</code> 时生效</td><td><code>&#39;Fluid&#39; | &#39;Fixed&#39;</code></td><td><code>&#39;Fluid&#39;</code></td><td>-</td></tr><tr><td>compact</td><td>是否启用紧凑布局</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>fixedHeader</td><td>是否固定 Header</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>fixedSiderbar</td><td>是否固定侧边栏</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>splitMenus</td><td>是否拆分一级菜单和子菜单，主要用于 <code>mix</code> 布局</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>suppressSiderWhenMenuEmpty</td><td>菜单为空时是否隐藏 Sider</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>siderWidth</td><td>侧边菜单宽度</td><td><code>number</code></td><td><code>256</code></td><td>-</td></tr><tr><td>collapsedWidth</td><td>侧边菜单收起宽度</td><td><code>number</code></td><td><code>64</code></td><td>-</td></tr><tr><td>collapsed</td><td>受控的侧边菜单收起状态</td><td><code>boolean</code></td><td>-</td><td>-</td></tr><tr><td>defaultCollapsed</td><td>默认收起状态</td><td><code>boolean</code></td><td>-</td><td>-</td></tr><tr><td>fixedHeaderSiderWidth</td><td>固定 Header 计算宽度时使用的侧边栏偏移量，通常由 <code>left</code> 布局内部计算</td><td><code>number</code></td><td>-</td><td>-</td></tr><tr><td>breakpoint</td><td>触发响应式收起的断点，设为 <code>false</code> 可禁用</td><td><code>Breakpoint | false</code></td><td><code>&#39;lg&#39;</code></td><td>-</td></tr><tr><td>disableMobile</td><td>是否禁用移动端响应式布局</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>pure</td><td>简约模式，只提供上下文，不渲染布局外框</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>loading</td><td>布局加载状态，开启后只展示 Loading</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>location</td><td>手动指定当前路由位置。通常无需设置，默认读取 Vue 应用实例上的 <code>$route</code>；未安装路由插件时可手动传入</td><td><code>RouterTypes[&#39;location&#39;]</code></td><td><code>$route</code> 或 <code>/</code></td><td>-</td></tr><tr><td>route</td><td>路由配置，<code>children</code> 会作为默认菜单数据</td><td><code>RouterTypes[&#39;route&#39;]</code></td><td>-</td><td>-</td></tr><tr><td>menu</td><td>菜单行为配置</td><td><code>MenuConfig</code></td><td>-</td><td>-</td></tr><tr><td>menuData</td><td>直接传入菜单数据。Vue 项目推荐在路由守卫或 store 中加载菜单并注册路由后传入</td><td><code>MenuDataItem[]</code></td><td>-</td><td>-</td></tr><tr><td>menuProps</td><td>透传给 <code>Menu</code> 的属性，参考 antdv-next Menu</td><td><code>MenuProps</code></td><td>-</td><td>-</td></tr><tr><td>mode</td><td>菜单模式，通常由布局内部决定</td><td><code>MenuProps[&#39;mode&#39;]</code></td><td>-</td><td>-</td></tr><tr><td>selectedKeys</td><td>受控的菜单选中项</td><td><code>string[]</code></td><td>-</td><td>-</td></tr><tr><td>openKeys</td><td>受控的菜单展开项，传 <code>false</code> 可关闭展开控制</td><td><code>string[] | false</code></td><td>-</td><td>-</td></tr><tr><td>menuDataRender</td><td>菜单数据渲染前的处理函数</td><td><code>(menuData: MenuDataItem[]) =&gt; MenuDataItem[]</code></td><td>-</td><td>-</td></tr><tr><td>postMenuData</td><td>菜单数据渲染前的最终处理函数，不再进行国际化和路径拼接处理</td><td><code>(menuData?: MenuDataItem[]) =&gt; MenuDataItem[]</code></td><td>-</td><td>-</td></tr><tr><td>formatMessage</td><td>菜单国际化格式化函数</td><td><code>(message: MessageDescriptor) =&gt; string | undefined</code></td><td>-</td><td>-</td></tr><tr><td>breadcrumbRender</td><td>自定义面包屑数据，返回 <code>false</code> 可隐藏面包屑</td><td><code>(routes: BreadcrumbProps[&#39;items&#39;]) =&gt; BreadcrumbProps[&#39;items&#39;] | false</code></td><td>-</td><td>-</td></tr><tr><td>breadcrumbProps</td><td>传递给 PageHeader 的面包屑配置</td><td><code>BreadcrumbProps &amp; LayoutBreadcrumbProps</code></td><td>-</td><td>-</td></tr><tr><td>itemRender</td><td>自定义面包屑项渲染</td><td><code>BreadcrumbProps[&#39;itemRender&#39;]</code></td><td>-</td><td>-</td></tr><tr><td>pageTitleRender</td><td>自定义页面标题</td><td><code>(options) =&gt; string | undefined | false</code></td><td>-</td><td>-</td></tr><tr><td>contentStyle</td><td>内容区样式</td><td><code>CSSProperties</code></td><td>-</td><td>-</td></tr><tr><td>bgLayoutImgList</td><td>布局背景图片列表</td><td><code>BgLayoutImg[]</code></td><td>-</td><td>-</td></tr><tr><td>colorPrimary</td><td>主色</td><td><code>string</code></td><td><code>#1677FF</code></td><td>-</td></tr><tr><td>colorWeak</td><td>是否启用色弱模式</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>iconfontUrl</td><td>自定义 iconfont Symbol 脚本地址</td><td><code>string</code></td><td>-</td><td>-</td></tr><tr><td>iconPrefixes</td><td>菜单字符串图标的 iconfont 前缀</td><td><code>string</code></td><td><code>&#39;icon-&#39;</code></td><td>-</td></tr><tr><td>token</td><td>Layout 组件级设计 Token</td><td><code>ProTokenType[&#39;layout&#39;]</code></td><td>-</td><td>-</td></tr><tr><td>stylish</td><td>自定义 Header、Sider 样式生成函数</td><td><code>{ header?: GenerateStyle; sider?: GenerateStyle }</code></td><td>-</td><td>-</td></tr><tr><td>avatarProps</td><td>头像配置</td><td><code>AvatarPropsType</code></td><td>-</td><td>-</td></tr><tr><td>appList</td><td>跨站点导航列表</td><td><code>AppListProps</code></td><td>-</td><td>-</td></tr><tr><td>itemClick</td><td>跨站点导航列表项点击回调，存在时不会自动跳转</td><td><code>(item: AppItemProps, popoverRef: ShallowRef) =&gt; void</code></td><td>-</td><td>-</td></tr><tr><td>links</td><td>侧边菜单底部快捷链接</td><td><code>VueNode[] | LinkItem[] | false</code></td><td>-</td><td>-</td></tr><tr><td>siderProps</td><td>透传给 <code>LayoutSider</code> 的属性</td><td><code>SiderProps</code></td><td>-</td><td>-</td></tr><tr><td>logoStyle</td><td>菜单 Logo 区域样式</td><td><code>CSSProperties</code></td><td>-</td><td>-</td></tr><tr><td>waterMarkProps</td><td>水印配置</td><td><code>WatermarkProps</code></td><td>-</td><td>-</td></tr><tr><td>errorBoundaryRender</td><td>自定义错误边界</td><td><code>ErrorBoundaryRender | false</code></td><td>-</td><td>-</td></tr><tr><td>tagsViewRender</td><td>自定义多标签页区域</td><td><code>TagsViewRender | false</code></td><td>-</td><td>-</td></tr><tr><td>siderMenuType</td><td>侧边菜单聚合模式，是 <code>menu.type</code> 的快捷方式</td><td><code>&#39;sub&#39; | &#39;group&#39;</code></td><td><code>&#39;sub&#39;</code></td><td>-</td></tr><tr><td>isChildrenLayout</td><td>是否作为子布局渲染</td><td><code>boolean</code></td><td>-</td><td>-</td></tr><tr><td>headerRender</td><td>自定义 Header，传 <code>false</code> 不渲染 Header</td><td><code>HeaderRender | false</code></td><td>-</td><td>-</td></tr><tr><td>menuRender</td><td>自定义菜单区域，传 <code>false</code> 不渲染菜单</td><td><code>MenuRender | false</code></td><td>-</td><td>-</td></tr><tr><td>menuHeaderRender</td><td>自定义菜单头 Logo 和标题区域，传 <code>false</code> 不渲染</td><td><code>MenuHeaderRender | false</code></td><td>-</td><td>-</td></tr><tr><td>menuItemRender</td><td>自定义叶子菜单项渲染</td><td><code>MenuItemRender | false</code></td><td>-</td><td>-</td></tr><tr><td>subMenuItemRender</td><td>自定义父级菜单项渲染</td><td><code>SubMenuItemRender | false</code></td><td>-</td><td>-</td></tr><tr><td>menuContentRender</td><td>自定义菜单内容区域</td><td><code>MenuContentRender | false</code></td><td>-</td><td>-</td></tr><tr><td>menuExtraRender</td><td>自定义菜单头下方额外区域</td><td><code>MenuExtraRender | false</code></td><td>-</td><td>-</td></tr><tr><td>menuFooterRender</td><td>自定义菜单底部区域</td><td><code>MenuFooterRender | false</code></td><td>-</td><td>-</td></tr><tr><td>collapsedButtonRender</td><td>自定义菜单收起按钮，传 <code>false</code> 不渲染</td><td><code>CollapsedButtonRender | false</code></td><td>-</td><td>-</td></tr><tr><td>actionsRender</td><td>自定义 Header 或 Sider 操作区</td><td><code>ActionsRender | false</code></td><td>-</td><td>-</td></tr><tr><td>appListRender</td><td>自定义跨站点导航渲染</td><td><code>AppListRender | false</code></td><td>-</td><td>-</td></tr><tr><td>headerTitleRender</td><td>自定义 Header 标题区域</td><td><code>HeaderTitleRender | false</code></td><td>-</td><td>-</td></tr><tr><td>headerContentRender</td><td>自定义 Header 内容区域</td><td><code>HeaderContentRender | false</code></td><td>-</td><td>-</td></tr><tr><td>footerRender</td><td>自定义页脚，传 <code>false</code> 不渲染页脚</td><td><code>FooterRender | false</code></td><td>-</td><td>-</td></tr><tr><td>pageHeaderRender</td><td>自定义 PageContainer 的 PageHeader 渲染</td><td><code>PageHeaderRender | false</code></td><td>-</td><td>-</td></tr><tr><td>footerToolbarContentRender</td><td>自定义 FooterToolbar 内容渲染</td><td><code>FooterToolbarContentRender</code></td><td>-</td><td>-</td></tr></tbody></table><p>除上表外，ProLayout 还会通过 <code>menuProps</code> 透传 antdv-next Menu 的属性；其中 <code>openKeys</code>、<code>openChange</code>、<code>title</code> 已由 ProLayout 单独接管。</p><h3 id="menu" tabindex="-1">menu <a class="header-anchor" href="#menu" aria-label="Permalink to &quot;menu {#menu}&quot;">​</a></h3><p><code>menu</code> 用于配置菜单展开行为、折叠行为和受控加载状态。异步菜单建议在 Vue Router 路由守卫或 store 中加载，ProLayout 只负责渲染已经准备好的 <code>route.children</code> 或 <code>menuData</code>。</p><table class="component-table-api"><thead><tr><th>参数</th><th>说明</th><th>类型</th><th>默认值</th><th>版本</th></tr></thead><tbody><tr><td>locale</td><td>是否启用菜单国际化</td><td><code>boolean</code></td><td><code>true</code></td><td>-</td></tr><tr><td>loading</td><td>菜单加载状态</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>defaultOpenAll</td><td>默认展开所有菜单项，仅在布局挂载前生效</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>autoClose</td><td>选中菜单后是否自动关闭移动端菜单，传 <code>false</code> 可关闭</td><td><code>boolean</code></td><td><code>true</code></td><td>-</td></tr><tr><td>ignoreFlatMenu</td><td>是否忽略用户手动折叠菜单的状态</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>hideMenuWhenCollapsed</td><td>收起时是否完全隐藏菜单内容</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>collapsedShowTitle</td><td>菜单收起时是否展示标题</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>type</td><td>菜单聚合模式</td><td><code>&#39;sub&#39; | &#39;group&#39;</code></td><td>-</td><td>-</td></tr></tbody></table><h3 id="settingdrawer" tabindex="-1">SettingDrawer <a class="header-anchor" href="#settingdrawer" aria-label="Permalink to &quot;SettingDrawer {#settingdrawer}&quot;">​</a></h3><p>SettingDrawer 是 ProLayout 的可视化配置面板，适合在演示站点或需要运行时配置布局的系统中使用。</p><table class="component-table-api"><thead><tr><th>属性</th><th>说明</th><th>类型</th><th>默认值</th><th>版本</th></tr></thead><tbody><tr><td>settings</td><td>当前布局配置</td><td><code>Partial&lt;ProSettings&gt;</code></td><td><code>defaultSettings</code></td><td>-</td></tr><tr><td>collapsed</td><td>是否收起配置面板</td><td><code>boolean</code></td><td>-</td><td>-</td></tr><tr><td>colorList</td><td>主题色候选列表，传 <code>false</code> 可隐藏主题色选择</td><td><code>{ key: string; color: string; title?: string }[] | false</code></td><td>内置色板</td><td>-</td></tr><tr><td>hideHintAlert</td><td>是否隐藏提示说明</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>hideCopyButton</td><td>是否隐藏复制配置按钮</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr></tbody></table><h3 id="events" tabindex="-1">事件 <a class="header-anchor" href="#events" aria-label="Permalink to &quot;事件 {#events}&quot;">​</a></h3><p>事件通过 Vue 事件语法注册，例如 <code>@collapse</code>、<code>@menu-header-click</code>、<code>@update:collapsed</code>。</p><table class="component-table-api"><thead><tr><th>事件</th><th>说明</th><th>类型</th><th>版本</th></tr></thead><tbody><tr><td>pageChange</td><td>页面位置变化时触发</td><td><code>(location?: RouterTypes[&#39;location&#39;]) =&gt; void</code></td><td>-</td></tr><tr><td>collapse</td><td>侧边菜单收起或展开时触发</td><td><code>(collapsed: boolean) =&gt; void</code></td><td>-</td></tr><tr><td>openChange</td><td>菜单展开项变化时触发</td><td><code>(openKeys?: Key[] | false) =&gt; void</code></td><td>-</td></tr><tr><td>select</td><td>菜单选中项变化时触发</td><td><code>(selectedKeys: Key[]) =&gt; void</code></td><td>-</td></tr><tr><td>menuHeaderClick</td><td>菜单头点击事件</td><td><code>(e: MouseEvent) =&gt; void</code></td><td>-</td></tr><tr><td>itemClick</td><td>跨站点导航列表项点击事件</td><td><code>(item: AppItemProps, popoverRef: ShallowRef) =&gt; void</code></td><td>-</td></tr><tr><td>SettingDrawer: settingChange</td><td>SettingDrawer 配置变化时触发</td><td><code>(settings: Partial&lt;ProSettings&gt;) =&gt; void</code></td><td>-</td></tr><tr><td>SettingDrawer: collapse</td><td>SettingDrawer 展开收起变化时触发</td><td><code>(collapsed: boolean) =&gt; void</code></td><td>-</td></tr><tr><td>SettingDrawer: update:collapsed</td><td><code>v-model:collapsed</code> 更新事件</td><td><code>(collapsed: boolean) =&gt; void</code></td><td>-</td></tr></tbody></table><h3 id="slots" tabindex="-1">插槽 <a class="header-anchor" href="#slots" aria-label="Permalink to &quot;插槽 {#slots}&quot;">​</a></h3><table class="component-table-api"><thead><tr><th>插槽</th><th>说明</th><th>类型</th><th>版本</th></tr></thead><tbody><tr><td>headerRender</td><td>自定义 Header 渲染</td><td><code>HeaderRender</code></td><td>-</td></tr><tr><td>menuRender</td><td>自定义菜单区域渲染</td><td><code>MenuRender</code></td><td>-</td></tr><tr><td>menuHeaderRender</td><td>自定义菜单头渲染</td><td><code>MenuHeaderRender</code></td><td>-</td></tr><tr><td>headerTitleRender</td><td>自定义 Header 标题渲染</td><td><code>HeaderTitleRender</code></td><td>-</td></tr><tr><td>headerContentRender</td><td>自定义 Header 内容渲染</td><td><code>HeaderContentRender</code></td><td>-</td></tr><tr><td>actionsRender</td><td>自定义操作区渲染</td><td><code>ActionsRender</code></td><td>-</td></tr><tr><td>footerRender</td><td>自定义页脚渲染</td><td><code>FooterRender</code></td><td>-</td></tr><tr><td>tagsViewRender</td><td>自定义多标签页区域渲染</td><td><code>TagsViewRender</code></td><td>-</td></tr><tr><td>footerToolbarContentRender</td><td>自定义 FooterToolbar 内容渲染</td><td><code>FooterToolbarContentRender</code></td><td>-</td></tr><tr><td>collapsedButtonRender</td><td>自定义菜单收起按钮渲染</td><td><code>CollapsedButtonRender</code></td><td>-</td></tr><tr><td>errorBoundaryRender</td><td>自定义错误边界渲染</td><td><code>ErrorBoundaryRender</code></td><td>-</td></tr><tr><td>appListRender</td><td>自定义跨站点导航列表渲染</td><td><code>AppListRender</code></td><td>-</td></tr><tr><td>menuItemRender</td><td>自定义叶子菜单项渲染</td><td><code>MenuItemRender</code></td><td>-</td></tr><tr><td>subMenuItemRender</td><td>自定义父级菜单项渲染</td><td><code>SubMenuItemRender</code></td><td>-</td></tr><tr><td>menuContentRender</td><td>自定义菜单内容区域渲染</td><td><code>MenuContentRender</code></td><td>-</td></tr><tr><td>menuFooterRender</td><td>自定义菜单底部区域渲染</td><td><code>MenuFooterRender</code></td><td>-</td></tr><tr><td>menuExtraRender</td><td>自定义菜单头下方额外区域渲染</td><td><code>MenuExtraRender</code></td><td>-</td></tr><tr><td>pageHeaderRender</td><td>自定义 PageContainer 的 PageHeader 渲染</td><td><code>PageHeaderRender</code></td><td>-</td></tr></tbody></table><h2 id="theme-variables" tabindex="-1">主题变量（Design Token） <a class="header-anchor" href="#theme-variables" aria-label="Permalink to &quot;主题变量（Design Token）{#theme-variables}&quot;">​</a></h2><p>Token 是设计系统的基本元素，可以通过 <code>token</code> 属性或 ProConfigProvider 修改 ProLayout 的 Header、Sider、内容区和菜单颜色。</p>`,18),a(`p`,null,[u(p,{component:`ProLayout`})]),s[4]||=r(`<h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ {#faq}&quot;">​</a></h2><h3 id="layout-mode" tabindex="-1">如何选择布局形态？ <a class="header-anchor" href="#layout-mode" aria-label="Permalink to &quot;如何选择布局形态？ {#layout-mode}&quot;">​</a></h3><ul><li><code>side</code>：最常见的中后台侧边菜单布局。</li><li><code>top</code>：导航项较少、希望内容区横向居中的顶部导航布局。</li><li><code>mix</code>：顶部一级导航配合侧边子菜单，适合一级模块较少但二级页面较多的系统。</li><li><code>left</code>：一级菜单固定在最左侧，二级菜单在旁边展开，适合需要频繁切换一级业务模块的系统。</li></ul><h3 id="custom-layout" tabindex="-1">如何隐藏不需要的区域？ <a class="header-anchor" href="#custom-layout" aria-label="Permalink to &quot;如何隐藏不需要的区域？ {#custom-layout}&quot;">​</a></h3><p>ProLayout 提供了一组 <code>xxxRender</code> API 来控制各个区域。传入函数可以自定义渲染，传入 <code>false</code> 可以关闭对应区域。</p><ul><li><code>headerRender</code> 可以自定义或关闭顶栏。</li><li><code>footerRender</code> 可以自定义或关闭页脚。</li><li><code>menuRender</code> 可以自定义或关闭菜单区域。</li><li><code>menuHeaderRender</code> 可以自定义或关闭菜单头区域。</li><li><code>menuExtraRender</code> 可以在菜单头和菜单之间增加额外内容。</li><li><code>collapsedButtonRender</code> 可以自定义或关闭菜单折叠按钮。</li></ul><p><img src="https://gw.alipayobjects.com/zos/antfincdn/mCXDkK2pJ0/60298863-F5A5-4af2-923A-13EF912DB0E1.png" alt="setting-drawer-render"></p>`,7)])}}});export{p as default};